import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuthStore } from './store/authStore';
import AppLayout from './components/layout/AppLayout';
import LoginForm from './components/auth/LoginForm';
import Dashboard from './components/dashboard/Dashboard';
import CourseList from './components/courses/CourseList';
import Calendar from './components/calendar/Calendar';
import ChatWindow from './components/chat/ChatWindow';
import VideoPlayer from './components/video/VideoPlayer';
import AssignmentCard from './components/assignments/AssignmentCard';

// Mock data
import { Course, Assignment, CalendarEvent, Message, User } from './types';

const mockCourses: Course[] = [
  {
    id: '1',
    title: 'Advanced Mathematics',
    description: 'Comprehensive study of calculus, linear algebra, and differential equations.',
    code: 'MATH-301',
    credits: 4,
    instructor: {
      id: '1',
      email: 'prof.smith@university.edu',
      firstName: 'Dr. Sarah',
      lastName: 'Smith',
      role: 'teacher',
      avatar: 'https://via.placeholder.com/150',
      isActive: true,
      createdAt: '2023-01-01T00:00:00Z',
      updatedAt: '2023-01-01T00:00:00Z',
    },
    students: [],
    startDate: '2024-01-15',
    endDate: '2024-05-15',
    schedule: [],
    status: 'active',
    createdAt: '2023-01-01T00:00:00Z',
    updatedAt: '2023-01-01T00:00:00Z',
  },
  {
    id: '2',
    title: 'Computer Science Fundamentals',
    description: 'Introduction to programming, data structures, and algorithms.',
    code: 'CS-101',
    credits: 3,
    instructor: {
      id: '2',
      email: 'prof.johnson@university.edu',
      firstName: 'Prof. Michael',
      lastName: 'Johnson',
      role: 'teacher',
      avatar: 'https://via.placeholder.com/150',
      isActive: true,
      createdAt: '2023-01-01T00:00:00Z',
      updatedAt: '2023-01-01T00:00:00Z',
    },
    students: [],
    startDate: '2024-01-10',
    endDate: '2024-04-30',
    schedule: [],
    status: 'active',
    createdAt: '2023-01-01T00:00:00Z',
    updatedAt: '2023-01-01T00:00:00Z',
  },
];

const mockAssignments: Assignment[] = [
  {
    id: '1',
    title: 'Linear Algebra Problem Set',
    description: 'Solve the following linear algebra problems and submit your solutions.',
    course: mockCourses[0],
    dueDate: '2024-01-20T23:59:00Z',
    maxPoints: 100,
    type: 'assignment',
    isPublished: true,
    allowLateSubmission: true,
    createdAt: '2024-01-01T00:00:00Z',
    updatedAt: '2024-01-01T00:00:00Z',
  },
  {
    id: '2',
    title: 'Programming Project',
    description: 'Implement a sorting algorithm and analyze its time complexity.',
    course: mockCourses[1],
    dueDate: '2024-01-25T23:59:00Z',
    maxPoints: 150,
    type: 'project',
    isPublished: true,
    allowLateSubmission: false,
    createdAt: '2024-01-01T00:00:00Z',
    updatedAt: '2024-01-01T00:00:00Z',
  },
];

const mockEvents: CalendarEvent[] = [
  {
    id: '1',
    title: 'Math Lecture',
    description: 'Advanced Calculus - Integration Techniques',
    start: '2024-01-15T10:00:00Z',
    end: '2024-01-15T11:30:00Z',
    type: 'class',
    location: 'Room 201',
    isAllDay: false,
    color: '#1976d2',
    createdBy: {
      id: '1',
      email: 'admin@university.edu',
      firstName: 'Admin',
      lastName: 'User',
      role: 'admin',
      isActive: true,
      createdAt: '2023-01-01T00:00:00Z',
      updatedAt: '2023-01-01T00:00:00Z',
    },
    createdAt: '2024-01-01T00:00:00Z',
    updatedAt: '2024-01-01T00:00:00Z',
  },
];

const mockMessages: Message[] = [
  {
    id: '1',
    sender: {
      id: '1',
      email: 'student@university.edu',
      firstName: 'John',
      lastName: 'Doe',
      role: 'student',
      isActive: true,
      createdAt: '2023-01-01T00:00:00Z',
      updatedAt: '2023-01-01T00:00:00Z',
    },
    content: 'Hello, I have a question about the assignment.',
    type: 'direct',
    isRead: false,
    createdAt: '2024-01-15T10:00:00Z',
  },
];

const mockUser: User = {
  id: '1',
  email: 'student@university.edu',
  firstName: 'John',
  lastName: 'Doe',
  role: 'student',
  avatar: 'https://via.placeholder.com/150',
  isActive: true,
  createdAt: '2023-01-01T00:00:00Z',
  updatedAt: '2023-01-01T00:00:00Z',
};

const App: React.FC = () => {
  const { isAuthenticated } = useAuthStore();

  if (!isAuthenticated) {
    return <LoginForm />;
  }

  return (
    <AppLayout>
      <Routes>
        <Route path="/" element={<Navigate to="/dashboard" replace />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route 
          path="/courses" 
          element={
            <CourseList 
              courses={mockCourses}
              onCourseClick={(id) => console.log('Course clicked:', id)}
              onEnroll={(id) => console.log('Enroll in course:', id)}
              onCreateCourse={() => console.log('Create course')}
              onEditCourse={(id) => console.log('Edit course:', id)}
              onDeleteCourse={(id) => console.log('Delete course:', id)}
            />
          } 
        />
        <Route 
          path="/assignments" 
          element={
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '16px' }}>
              {mockAssignments.map(assignment => (
                <AssignmentCard
                  key={assignment.id}
                  assignment={assignment}
                  currentUser={mockUser}
                  onView={(id) => console.log('View assignment:', id)}
                  onEdit={(id) => console.log('Edit assignment:', id)}
                  onDelete={(id) => console.log('Delete assignment:', id)}
                  onSubmit={(id) => console.log('Submit assignment:', id)}
                />
              ))}
            </div>
          } 
        />
        <Route 
          path="/videos" 
          element={
            <VideoPlayer
              url="https://www.youtube.com/watch?v=dQw4w9WgXcQ"
              title="Sample Video Lecture"
              description="This is a sample video lecture for demonstration purposes."
              duration={212}
            />
          } 
        />
        <Route 
          path="/calendar" 
          element={
            <Calendar
              events={mockEvents}
              onEventClick={(event) => console.log('Event clicked:', event)}
              onCreateEvent={(event) => console.log('Create event:', event)}
            />
          } 
        />
        <Route 
          path="/messages" 
          element={
            <ChatWindow
              currentUser={mockUser}
              messages={mockMessages}
              onSendMessage={(content, attachments) => console.log('Send message:', content, attachments)}
              onTyping={(isTyping) => console.log('Typing:', isTyping)}
              isOnline={true}
            />
          } 
        />
        <Route path="/library" element={<div>Library Component</div>} />
        <Route path="/grades" element={<div>Grades Component</div>} />
        <Route path="/bookmarks" element={<div>Bookmarks Component</div>} />
        <Route path="/students" element={<div>Students Component</div>} />
        <Route path="/analytics" element={<div>Analytics Component</div>} />
        <Route path="/profile" element={<div>Profile Component</div>} />
        <Route path="/settings" element={<div>Settings Component</div>} />
      </Routes>
    </AppLayout>
  );
};

export default App;
